import React, { useState, useEffect } from 'react';
import { useLocation, useParams, useNavigate } from 'react-router-dom';

const StudySession = () => {
  const { day } = useParams();
  const { state } = useLocation();
  const navigate = useNavigate();

  const [timeLeft, setTimeLeft] = useState(1800); 
  const [isActive, setIsActive] = useState(false);
  const [showAIField, setShowAIField] = useState(false);
  const [userAnswer, setUserAnswer] = useState('');
  
  // New States for Key Points and AI Challenge
  const [keyPoints, setKeyPoints] = useState([]);
  const [challengeQuestion, setChallengeQuestion] = useState("");

  // 1. Generate Key Points on Load
  useEffect(() => {
    // In a real app, this would be a Gemini API call: fetchKeyPoints(state.topic)
    const mockPoints = [
      `Definition and core purpose of ${state?.topic}`,
      `Top 3 use-cases in real-world development`,
      `Common errors/pitfalls to avoid`
    ];
    setKeyPoints(mockPoints);
  }, [state?.topic]);

  // 2. Timer Logic
  useEffect(() => {
    let interval = null;
    if (isActive && timeLeft > 0) {
      interval = setInterval(() => setTimeLeft(t => t - 1), 1000);
    }
    return () => clearInterval(interval);
  }, [isActive, timeLeft]);

  // 3. The "2-Second" Fast Forward (For testing/Quick move)
  const fastForward = () => {
    setTimeLeft(0);
    handleFinish('completed');
  };

  const handleFinish = (status) => {
    setIsActive(false);
    // Generate a CHALLENGE question, not a summary question
    setChallengeQuestion(`Explain a scenario where ${state?.topic} would FAIL or cause a bug. How would you fix it?`);
    setShowAIField(true);
  };

  const submitToAI = () => {
    if (userAnswer.length < 20) {
      alert("Your answer is too short. The AI knows you're cutting corners! Explain more.");
      return;
    }
    alert("Knowledge verified. Day " + day + " marked as Complete.");
    navigate('/dashboard');
  };

  return (
    <div style={{ padding: '30px', fontFamily: 'sans-serif', backgroundColor: '#f0f2f5', minHeight: '100vh' }}>
      <div style={{ maxWidth: '700px', margin: '0 auto', background: 'white', padding: '25px', borderRadius: '12px' }}>
        
        <h2>Day {day}: {state?.topic}</h2>
        
        {/* KEY POINTS SECTION */}
        <div style={{ background: '#fff9db', padding: '15px', borderRadius: '8px', borderLeft: '5px solid #f1c40f', marginBottom: '20px' }}>
          <h4 style={{ marginTop: 0 }}>Study These Key Points:</h4>
          <ul>
            {keyPoints.map((p, i) => <li key={i}>{p}</li>)}
          </ul>
        </div>

        <div style={{ textAlign: 'center', marginBottom: '20px' }}>
          <div style={{ fontSize: '50px', fontWeight: 'bold' }}>{Math.floor(timeLeft/60)}:{String(timeLeft%60).padStart(2, '0')}</div>
          
          <button onClick={() => setIsActive(!isActive)} style={{ padding: '10px 20px', backgroundColor: '#2ecc71', color: 'white', border: 'none', borderRadius: '5px', marginRight: '10px' }}>
            {isActive ? 'Pause' : 'Start Timer'}
          </button>

          {/* THE 2-SECOND BUTTON YOU ASKED FOR */}
          <button onClick={fastForward} style={{ padding: '10px 20px', backgroundColor: '#9b59b6', color: 'white', border: 'none', borderRadius: '5px' }}>
            Test: Finish in 2s
          </button>
        </div>

        {showAIField && (
          <div style={{ borderTop: '2px solid #eee', paddingTop: '20px', marginTop: '20px' }}>
            <div style={{ backgroundColor: '#e8f4fd', padding: '15px', borderRadius: '8px', marginBottom: '15px' }}>
              <strong>AI Proctor:</strong> {challengeQuestion}
            </div>
            
            <textarea 
              placeholder="Don't just copy the points above. Explain the 'Why'..."
              value={userAnswer}
              onChange={(e) => setUserAnswer(e.target.value)}
              style={{ width: '100%', height: '100px', padding: '10px', boxSizing: 'border-box' }}
            />
            
            <button 
              onClick={submitToAI}
              style={{ width: '100%', padding: '15px', backgroundColor: '#2c3e50', color: 'white', border: 'none', borderRadius: '5px', marginTop: '10px', cursor: 'pointer' }}
            >
              Verify Knowledge & Finish
            </button>
          </div>
        )}
      </div>
    </div>
  );
};

export default StudySession;
